    while (T--) {
        long N, X;
        cin >> N >> X;

        vector<long long> a(N);
        int indexOfZero = -1;
        for (int i = 0; i < N; i++) {
            cin >> a[i];
            if(indexOfZero == -1 && a[i] == 0){
                indexOfZero = i;
            }
        }
        if(X==0){
            if(indexOfZero > 3){
                cout<<"1 2 3 "<<indexOfZero+1;
            }else{
                cout<<"1 2 3 4";
            }
            continue;
        }

        unordered_map<long long, pair<int, int>> beauty_pairs; // Store pairs of beauty values and their indices
        bool found = false;

        for (int i = 0; i < N; i++) {
            if(a[i] == 0){
                continue;
            }
            for (int j = i + 1; j < N; j++) {
                if(a[j] == 0){
                    continue;
                }
                long long product = (long long)a[i] * a[j];
                if (X % product == 0) {
                    long long target = X / product;
                    if (beauty_pairs.find(target) != beauty_pairs.end() &&
                        (beauty_pairs[target].first != i && beauty_pairs[target].second != i) &&
                        (beauty_pairs[target].first != j && beauty_pairs[target].second != j)) {
                        // Found a valid combination
                        found = true;
                        int arrSize = 4;
                        int arr[] = {i+1, j+1, beauty_pairs[target].first + 1, beauty_pairs[target].second + 1};
                        sort(arr, arr + arrSize);
                        int index = 0;
                        while (arrSize--) {
                            cout << arr[index++];
                            if (index != 4) {
                                cout << " ";
                            } else {
                                cout << endl;
                            }
                        }
                        break;
                    }

                }
                auto it = beauty_pairs.find(product);

                if (it == beauty_pairs.end()) {
                  beauty_pairs[product] = {i, j};
                }

            }
            if (found) break;
        }

        if (!found) {
            cout << "-1" << endl;
        }
    }

    return 0;
}

